export const getListCertificadosUrl = (params?: ListCertificadosParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/certificados?${stringifiedParams}` : `/api/certificados`
}

/**
 * @summary List all certificates
 */
export const listCertificados = async (params?: ListCertificadosParams, options?: RequestInit): Promise<Certificado[]> => {

  return customFetch<Certificado[]>(getListCertificadosUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getListCertificadosQueryKey = (params?: ListCertificadosParams,) => {
    return [
    `/api/certificados`, ...(params ? [params] : [])
    ] as const;
    }


export const getListCertificadosQueryOptions = <TData = Awaited<ReturnType<typeof listCertificados>>, TError = ErrorType<unknown>>(params?: ListCertificadosParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof listCertificados>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getListCertificadosQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof listCertificados>>> = ({ signal }) => listCertificados(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof listCertificados>>, TError, TData> & { queryKey: QueryKey }
}

