export const getCreateCertificadoUrl = () => {




  return `/api/certificados`
}

/**
 * @summary Issue a certificate
 */
export const createCertificado = async (certificadoInput: CertificadoInput, options?: RequestInit): Promise<Certificado> => {

  return customFetch<Certificado>(getCreateCertificadoUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(certificadoInput)
  }
);}




export const getCreateCertificadoMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof createCertificado>>, TError,{data: BodyType<CertificadoInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof createCertificado>>, TError,{data: BodyType<CertificadoInput>}, TContext> => {

const mutationKey = ['createCertificado'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof createCertificado>>, {data: BodyType<CertificadoInput>}> = (props) => {
          const {data} = props ?? {};

          return  createCertificado(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type CreateCertificadoMutationResult = NonNullable<Awaited<ReturnType<typeof createCertificado>>>
    export type CreateCertificadoMutationBody = BodyType<CertificadoInput>
    export type CreateCertificadoMutationError = ErrorType<unknown>

    /**
 * @summary Issue a certificate
 */
export const useCreateCertificado = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof createCertificado>>, TError,{data: BodyType<CertificadoInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof createCertificado>>,
        TError,
        {data: BodyType<CertificadoInput>},
        TContext
      > => {
      return useMutation(getCreateCertificadoMutationOptions(options));
    }

